import{_ as e,o as t,c as o,a3 as s}from"./chunks/framework.CVjg771q.js";const _=JSON.parse('{"title":"生肖 · 狗","description":"戌狗——忠诚可靠，灵敏通人性","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"生肖 · 狗","description":"戌狗——忠诚可靠，灵敏通人性"},"headers":[],"relativePath":"changshi/shengxiao/gou.md","filePath":"changshi/shengxiao/gou.md","lastUpdated":1779783531000}'),n={name:"changshi/shengxiao/gou.md"};function r(i,a,p,c,h,l){return t(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="戌狗" tabindex="-1">戌狗 <a class="header-anchor" href="#戌狗" aria-label="Permalink to &quot;戌狗&quot;">​</a></h1><blockquote><p>地支「戌」· 戌时（19:00–21:00）· 五行属土 · 阴阳为阳</p></blockquote><p>狗忠诚可靠，灵敏通人性，戌时狗的警惕性、机敏性最高。在日常生活中，狗与人类十分亲近，是陪伴人类的朋友。《陈书》记载：「线彪败后，与妻杨氏去，唯所养一犬黄仓在前后，未尝离。」狗还有忠义、富贵、吉利的寓意，民间有「猫来穷，狗来富」的说法。</p><h2 id="生肖故事-一顿一盆-vs-一顿一灯盏" tabindex="-1">生肖故事：一顿一盆 vs 一顿一灯盏 <a class="header-anchor" href="#生肖故事-一顿一盆-vs-一顿一灯盏" aria-label="Permalink to &quot;生肖故事：一顿一盆 vs 一顿一灯盏&quot;">​</a></h2><p>玉帝挑选十二生肖依据的是动物们对人类是否有贡献。选十二生肖之前，狗和猫原本很和谐，但为了争夺一席之地，它们开始不断斗嘴。猫认为狗成天趴在门口晒太阳，吃得多，对人类社会没什么贡献。狗也不甘示弱，说猫挑肥拣瘦，总是围着主人喵喵叫，还总是睡懒觉。</p><p>双方争执不下，前去请玉帝评理。玉帝问狗：「你每顿吃多少？」狗老实回答：「我每日看门守园，一顿吃一盆。」玉帝又问猫：「你一顿吃多少？」猫灵机一动说：「我擅长抓老鼠，自食其力，每顿只吃一灯盏即可。」玉帝定夺道：「猫为民除害，吃得少干得多，贡献自然比狗大！」</p><p>狗一听气愤极了，想理论也不知从何下口。一出玉皇大殿，狗就向猫扑过去。猫灵巧地躲开，一路跑回了家，进了家也不敢露面。到了争夺生肖排位当天，天官将玉帝的旨意理解成了排队制——谁先到谁排前面。狗得知后，趁猫躲避它的机会立马赶到了天宫，最终排到了生肖第十一位。</p><p><strong>生肖习俗</strong>：端午节四川古蔺县流行「挂艾狗」——用陈艾和菖蒲扎成狗形，挂于门口辟邪求福。江苏丹徒县在农历四月初八过「赶狗节」——家家捏泥狗和面狗。</p>',8)])])}const g=e(n,[["render",r]]);export{_ as __pageData,g as default};
